security_findings.evidence:
UNPATCHED ControllerConfigureForTransfer speed register programming (no SPKLEN writes):

  // Registers 0x14/0x18 (Standard Speed) - ALWAYS written
  HWREG<unsigned long>::Write(*(arg1 + 8) + 0x14, *(arg1 + 0x70));
  HWREG<unsigned long>::Write(*(arg1 + 8) + 0x18, *(arg1 + 0x74));
  // Register 0x1c (Fast or FastPlus) - ALWAYS written
  HWREG<unsigned long>::Write(rcx_25, *(arg1 + 0x88));  // or 0x7c
  // Register 0x20 - ALWAYS written
  HWREG<unsigned long>::Write(*(arg1 + 8) + 0x20, rdx_11);
  // Registers 0x24/0x28 (High Speed) - ALWAYS written regardless of mode
  HWREG<unsigned long>::Write(*(arg1 + 8) + 0x24, *(arg1 + 0x94));
  HWREG<unsigned long>::Write(*(arg1 + 8) + 0x28, *(arg1 + 0x98));
  // NO write to 0xA0 (SPKLEN) or 0xA4 (HS_SPKLEN)!

PATCHED ControllerConfigureForTransfer (mode-specific writes + SPKLEN):

  if (rax_16 == 1) {  // Standard Speed
    HWREG<unsigned long>::Write(*(arg1 + 8) + 0x14, *(arg1 + 0x70));
    HWREG<unsigned long>::Write(*(arg1 + 8) + 0x18, *(arg1 + 0x74));
    HWREG<unsigned long>::Write(*(arg1 + 8) + 0xa0, *(arg1 + 0x7c));  // SPKLEN!
    HWREG<unsigned long>::Write(*(arg1 + 8) + 0x7c, *(arg1 + 0x78));
  } else if (rax_16 == 2) {  // Fast/FastPlus
    ...
    HWREG<unsigned long>::Write(*(arg1 + 8) + 0xa0, *(arg1 + 0x9c));  // SPKLEN!
    ...
  } else if (rax_16 == 3) {  // HighSpeed
    ...
    HWREG<unsigned long>::Write(*(arg1 + 8) + 0xa0, *(arg1 + 0x8c));  // SPKLEN!
    HWREG<unsigned long>::Write(*(arg1 + 8) + 0xa4, *(arg1 + 0xac));  // HS_SPKLEN!
    ...
  }
